# Add to the governance portal ticket when AI assistance was used
@dataclass
class AIAssistedContributionFields:
    model_used: str              # e.g. "GitHub Copilot", "Claude claude-sonnet-4-6"
    prompt_contained_internal_code: bool
    prompt_contained_internal_specs: bool
    engineer_reviewed_output: bool   # line-by-line review before submission
    verbatim_check_performed: bool   # manual review for near-verbatim reproduction

    def requires_elevated_review(self) -> bool:
        return (
            self.prompt_contained_internal_code
            or self.prompt_contained_internal_specs
            or not self.engineer_reviewed_output
            or not self.verbatim_check_performed
        )

    def review_notes(self) -> str:
        issues = []
        if self.prompt_contained_internal_code:
            issues.append("Prompt included internal code — IP contamination risk")
        if not self.engineer_reviewed_output:
            issues.append("Output was not line-by-line reviewed — review required before submission")
        if not self.verbatim_check_performed:
            issues.append("Verbatim reproduction check not performed")
        return "; ".join(issues) if issues else "AI assistance declared, controls applied."

from dataclasses import dataclass

@dataclass
class ExportControlCheck:
    contribution_id: str
    contains_encryption: bool
    targets_controlled_hardware: bool
    implements_novel_ai_architecture: bool
    export_counsel_reviewed: bool = False
    cleared: bool = False
    notes: str = ""

    def requires_export_review(self) -> bool:
        return (
            self.contains_encryption
            or self.targets_controlled_hardware
            or self.implements_novel_ai_architecture
        )

    def can_publish(self) -> bool:
        if not self.requires_export_review():
            return True
        return self.export_counsel_reviewed and self.cleared

    def blocker(self) -> str | None:
        if not self.requires_export_review():
            return None
        if not self.export_counsel_reviewed:
            return "Export control counsel review required before publication."
        if not self.cleared:
            return f"Export control review completed but not cleared: {self.notes}"
        return None
